.load extensions/epub/target/wasm32-wasip2/release/epub_extension.component.wasm

/* EPUB metadata extraction.
 *
 * Three fixtures, all hex literals (single-line to dodge cli line
 * continuation quirks):
 *
 *   epub_full:   a synthesized 1412-byte EPUB 3 archive carrying
 *                title="The Smoke Book", creators=[Alice Author,
 *                Bob Writer], contributor=Carol Editor, language=en,
 *                publisher=Smoke Press, date=2024-03-15,
 *                identifier=urn:isbn:9781234567897,
 *                subjects=[Testing, SQLite, EPUB], description set,
 *                rights=Public Domain, 3 spine entries.
 *
 *   plain_zip:   a 174-byte ZIP archive that has no META-INF/
 *                container.xml entry. Parses as ZIP but fails the
 *                EPUB rootfile lookup -> every fn returns NULL.
 *
 *   random:      12 bytes of 0xAA -- doesn't match the ZIP local
 *                file header signature (PK\x03\x04) so ZipArchive
 *                returns InvalidArchive and we collapse to NULL.
 */

------------------------------------------------------------------
-- Acceptance 1: full EPUB -> single-value scalars
------------------------------------------------------------------
SELECT epub_title(x'');
SELECT epub_language(x'');
SELECT epub_publisher(x'');
SELECT epub_published_date(x'');
SELECT epub_identifier(x'');
SELECT epub_chapter_count(x'');

------------------------------------------------------------------
-- Acceptance 2: full EPUB -> JSON-array scalars (authors, subjects)
------------------------------------------------------------------
SELECT epub_authors(x'');
SELECT epub_subjects(x'');

------------------------------------------------------------------
-- Acceptance 3: epub_metadata is parseable JSON; spot-check a few keys
------------------------------------------------------------------
SELECT json_extract(epub_metadata(x''), '$.title');
SELECT json_extract(epub_metadata(x''), '$.chapter_count');
SELECT json_extract(epub_metadata(x''), '$.version');

------------------------------------------------------------------
-- Acceptance 4: ZIP without container.xml -> every fn returns NULL
------------------------------------------------------------------
SELECT epub_title(x'504B0304140000000800EE75D45CDFA9BE7816000000140000000A000000726561646D652E747874CB2A2D2E514854A8CA2CD051C8CB2F51482D284D0200504B01021403140000000800EE75D45CDFA9BE7816000000140000000A0000000000000000000000800100000000726561646D652E747874504B05060000000001000100380000003E0000000000');
SELECT epub_language(x'504B0304140000000800EE75D45CDFA9BE7816000000140000000A000000726561646D652E747874CB2A2D2E514854A8CA2CD051C8CB2F51482D284D0200504B01021403140000000800EE75D45CDFA9BE7816000000140000000A0000000000000000000000800100000000726561646D652E747874504B05060000000001000100380000003E0000000000');
SELECT epub_metadata(x'504B0304140000000800EE75D45CDFA9BE7816000000140000000A000000726561646D652E747874CB2A2D2E514854A8CA2CD051C8CB2F51482D284D0200504B01021403140000000800EE75D45CDFA9BE7816000000140000000A0000000000000000000000800100000000726561646D652E747874504B05060000000001000100380000003E0000000000');

------------------------------------------------------------------
-- Acceptance 5: random bytes -> NULL on every fn (no error)
------------------------------------------------------------------
SELECT epub_title(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT epub_authors(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT epub_language(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT epub_publisher(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT epub_published_date(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT epub_identifier(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT epub_subjects(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT epub_chapter_count(x'AAAAAAAAAAAAAAAAAAAAAAAA');
SELECT epub_metadata(x'AAAAAAAAAAAAAAAAAAAAAAAA');

------------------------------------------------------------------
-- Acceptance 6: NULL input -> NULL on every fn
------------------------------------------------------------------
SELECT epub_title(NULL);
SELECT epub_authors(NULL);
SELECT epub_metadata(NULL);

------------------------------------------------------------------
-- Acceptance 7: version is non-empty text
------------------------------------------------------------------
SELECT length(epub_version()) > 0;
